import React, { useEffect, useState } from 'react';
import { XYPlot, XAxis, YAxis, VerticalGridLines, HorizontalGridLines, VerticalBarSeries, VerticalBarSeriesCanvas, DiscreteColorLegend, LabelSeries, LineMarkSeries, Hint} from 'react-vis';

import fulldata from "./data";
import {processData1, processChartData, getBarchartData, removeDuplicates, sumOfData} from "./util";

function BarChart(props){
    const BarSeries = VerticalBarSeries;
    const [data1, setdata1] = useState(null)
    const [data2, setdata2] = useState(null)
    const [data3, setdata3] = useState(null)

    useEffect(()=>{
        var d1 = processData1(fulldata, null, "date_utc", "contextInfo", "username")
        setdata1(removeDuplicates(d1)) //day vs users
        setdata2(processData1(fulldata, null, "date_utc")) //day vs logentries
        var d3 = processData1(fulldata, null, "date_utc", "file", "fileSizeDwn")
        setdata3(d3) //day vs download size
    },[])

    const styles = {
      container:{
        width:"90%", 
        margin:"30px 0px", 
        alignItems:"center", 
        justifyContent:"center", 
        display:"flex", 
        flexDirection:"column",
        padding:"20px",
        border:"1px solid lightgrey",
        background:"beige",
        borderRadius: "10px"
      }
    }

    return (
      <div style={styles.container}>
        <XYPlot
          className="clustered-stacked-bar-chart-example"
          xType="ordinal"
          stackBy="y"
          width={800}
          height={300}
        >
          <DiscreteColorLegend
            style={{position: 'absolute', left: '50px', top: '10px'}}
            orientation="horizontal"
            items={[
              {
                title: 'Data downloaded in MB',
                color: '#12939A'
              },
              {
                title: 'Log entries',
                color: 'lightblue'
              },
              {
                title: 'Users',
                color: 'purple'
              }
            ]}
          />
          <VerticalGridLines />
          <HorizontalGridLines />
          <XAxis />
          <YAxis />
          <YAxis tickValues={[25,50,75,100,150]} orientation={"right"}/>
          {
            data3 &&
            <BarSeries
                className="area-elevated-line-series"
                data={getBarchartData(processChartData(data3, null, "fileSizeDwn"))}
            />
          }
          {
              data1 && 
                <LineMarkSeries
                cluster="2015"
                color="purple"
                data={getBarchartData(processChartData(data1))}
            />
          }
          {
              data2 && 
                <LineMarkSeries
                cluster="2015"
                color="lightblue"
                data={getBarchartData(processChartData(data2))}
            />
          }
        </XYPlot>
      </div>
    );
}

export default BarChart