import React, { useEffect, useState } from "react"
import './App.css';
import '../node_modules/react-vis/dist/style.css';

import fulldata from "./data";
import BarChart from "./BarChart"
import SunBurstChart from "./SunBurst";
import {processData, processChartData, processData1, chartParams, parseType, getChildData} from "./util";

function ChartsMain(props) {
  const [hoveredCell, setHoveredCell] =  useState(false)
  const [userData, setUserData] = useState(null);
  const [prevData, setPrevData] = useState(null)
  const [chartData, setChartData] = useState(null)
  const [selectedEle, setSelected] = useState(null);
  const [chartType, selectChartType] = useState(props.type);
  const [minVal, setMinVal] = useState(1);
  const [filterText, setFilterTextSelected] = useState("")

  const [xaxis, setAxisX] = useState(null);
  const [yaxis, setAxisY] = useState([]);

  useEffect(()=>{
    if(xaxis){
      let processedData = processData1(fulldata, xaxis[0], xaxis[1], yaxis[0], yaxis[1]);
      setUserData(processedData);
      processChartData(processedData, setChartData, yaxis[1])
      processForSelectedRecs(processedData)
    }
    setMinVal(1)
  },[xaxis, yaxis])
  

  const processForSelectedRecs = (recs)=>{
    let allData = {...recs}
    Object.keys(recs).forEach(key=>allData[key] = true)
    setSelected(allData);
  }

  const onCellSelect = (v)=>{
    if(!v.parent && prevData){
      setUserData(prevData);
      processChartData(prevData, setChartData, yaxis[1])
      processForSelectedRecs(prevData)
      setPrevData(null);
    }
    else if((v.parent && !prevData) || chartType=== "barchart"){
      let childData = getChildData(fulldata, xaxis, v.name);
      let processedData = processData1(childData, null, "date_utc", "file", "fileSizeDwn")
      setUserData(processedData);
      processChartData(processedData, setChartData, yaxis[1])
      processForSelectedRecs(processedData)
      setPrevData(userData);
    }
  }

  const toggleCheckbox = (ele, isChecked)=>{
    let allData = {...selectedEle};
    allData[ele] = isChecked;

    setSelected(allData)
    let fdata = {}
    Object.keys(userData).map(key=>{
      if(allData[key]){
        fdata[key] = userData[key]
      }
      return null
    })
    processChartData(fdata, setChartData, yaxis[1]);
  }

  const filterData = (val)=>{
    let fdata = {};
    Object.keys(userData).map(key=>{
      if(userData[key].length > val){
        fdata[key] = userData[key]
      }
      return null
    })
    processChartData(fdata, setChartData, yaxis[1]);
    processForSelectedRecs(fdata);
    setMinVal(val)
  }

  const styles = {
    container:{
      width:"90%", 
      margin:"30px 0px", 
      alignItems:"center", 
      justifyContent:"center", 
      display:"flex", 
      flexDirection:"column",
      padding:"20px",
      border:"1px solid lightgrey",
      background:"beige",
      borderRadius: "10px"
    }
  }

  return (
    <div className="App" style={styles.container}>      
      <div>
        <div className="d-flex">
          <div class="input-group m-3">
            <span class="input-group-text" id="basic-addon1">X-Axis</span>
            <select class="custom-select" onChange={(e)=>setAxisX(chartParams[e.target.value])}>
              <option selected>Open this select menu</option>
              {
                Object.keys(chartParams).map(val=><option value={val}>{val}</option>)
              }
            </select>
          </div>
          <div class="input-group m-3">
            <span class="input-group-text" id="basic-addon1">Y-Axis</span>
            <select class="custom-select" onChange={(e)=>setAxisY(chartParams[e.target.value])}>
              <option selected>Open this select menu</option>
              {
                Object.keys(chartParams).map(val=><option value={val}>{val}</option>)
              }
            </select>
          </div>
          <div class="input-group m-3">
          <span class="input-group-text" id="basic-addon1">Chart Type</span>
          <select class="custom-select" value={chartType} onChange={(e)=>selectChartType(e.target.value)}>
            <option value="sunburst">Sunburst</option>
            <option value="barchart">Barchart</option>
          </select>
        </div>
        </div>
      </div>
      <div className="col-10 row">
        {/* {
          xaxis && <p>{xaxis[1]} vs {yaxis ? <>{yaxis[1]}</> : <>"log entries"</>}</p>
        } */}
        <div className="col-lg-8 d-flex border border-end-0 border-secondary" style={{alignItems:"center", justifyContent:"center"}}>
        {
          chartData && chartType === "sunburst" &&
          <SunBurstChart data={parseType(chartData, yaxis[1])} xaxis = {xaxis} yaxis={yaxis} setHoveredCell={v=>setHoveredCell(v)} onCellSelect={v=>onCellSelect(v)} hoveredCell={hoveredCell}/>
        }
        {
          chartData && chartType === "barchart" &&
          <BarChart data={parseType(chartData, yaxis[1])} onDataSelect={(arg)=>onCellSelect(arg)} setHoveredCell={v=>setHoveredCell(v)} hoveredCell={hoveredCell} hideDataCell={(cell)=>{toggleCheckbox(cell,false)}}/>
        }
        </div>
        <div className="col-4 border border-secondary">
          {
            xaxis &&
            <div class="input-group m-3">
              <span class="input-group-text" id="basic-addon1">Min Value</span>
              <input type="number" min="1" max="100" value={minVal} class="form-control col-6" id="myRange"  onChange={(e) => filterData(e.target.value)}></input>
            </div>
          }
          {
            xaxis &&
            <div class="accordion col-12" id="accordionExample">
              <div class="card">
                <div class="card-header" id="headingOne">
                  <p class="text-left m-0" data-toggle="collapse" data-target="#collapseOne" aria-expanded="true" aria-controls="collapseOne">
                    Data Records Selected 
                    <i class="bi bi-chevron-down mx-2"></i>
                  </p>
                </div>

                <div id="collapseOne" class="collapse show" aria-labelledby="headingOne" data-parent="#accordionExample">
                  <div class="card-body" style={{maxHeight:"30vh", overflow:"auto", display:"flex", flexDirection:"column"}}>
                  <input type="text" vclass="custom-select mb-3" placeholder="enter text to filter" onChange={(e) => setFilterTextSelected(e.target.value)}></input>
                    {
                        selectedEle &&
                        Object.keys(selectedEle).map((user)=>{
                          if(!filterText || (filterText && user.toLocaleLowerCase().includes(filterText)))
                          {
                            return (
                              <label style={{textAlign:"left"}}>
                                <input type="checkbox"
                                  defaultChecked={selectedEle[user]}
                                  onChange={(e) => toggleCheckbox(user,e.target.checked)}
                                />
                                {" "+ user}
                              </label>
                            )
                          }
                        })
                      }
                  </div>
                </div>
              </div>
            </div>
          }
          
        </div>
      </div>
    </div>
  );
}

export default ChartsMain;
