import React, { useState } from 'react';
import {Sunburst, Hint} from 'react-vis';
import fulldata from "./data";
import {getChildData, processChartData, processData1} from "./util";

const tipStyle = {
    display: 'flex',
    color: '#fff',
    background: '#000',
    alignItems: 'center',
    padding: '5px'
};

function buildValue(hoveredCell) {
    const {radius, angle, angle0} = hoveredCell;
    const truedAngle = (angle + angle0) / 2;
    return {
        x: radius * Math.cos(truedAngle),
        y: radius * Math.sin(truedAngle)
    };
}
  
  

function SunburstChart(props){

    const getDataWithChildren = ()=>{
        props.data.children.map((child)=>{
            let cdata = getChildData(fulldata, props.xaxis, child.name);
            let pdata = processData1(cdata, null, "date_utc", "file", "fileSizeDwn")
            let children = processChartData(pdata).children
            children.map((c)=>c.clr = child.clr)
            child.children = children;
        })
        return props.data;
    }

    return (
        <Sunburst
            data={getDataWithChildren()}
            style={{stroke: '#fff'}}
            onValueMouseOver={v => props.setHoveredCell(v)}
            onValueMouseOut={v => props.setHoveredCell(false)}
            onValueClick={v=>props.onCellSelect(v)}
            height={500}
            margin={{top: 50, bottom: 50, left: 50, right: 50}}
            getSize={d => d.bigness}
            getColor={d => d.clr}
            width={500}
            >
            {props.hoveredCell ? (
                <Hint value={buildValue(props.hoveredCell)}>
                    <div style={tipStyle}>
                        <p> {props.hoveredCell.name} / value : {props.hoveredCell.bigness} </p>
                    </div>
                </Hint>
            ) : null}
        </Sunburst>
    )
}

export default SunburstChart