import React, { useEffect, useState } from "react"
import 'bootstrap';
import './App.css';
import '../node_modules/react-vis/dist/style.css';
import 'bootstrap/dist/css/bootstrap.min.css';

import Chart from "./ChartsMain";
import CustomChart from "./CustomChart";

function App() {
  const [charts, addChart] = useState([])

  const addNewChart = ()=>{
    let allCharts = [...charts];
    allCharts.push(<Chart xkey="contextInfo" xparam="tcode" ykey="file" yparam="fileSizeDwn" type="sunburst"/>)
    addChart(allCharts)
  }
  return (
    <div className="App" style={{width:"100%", alignItems:"center", justifyContent:"center", display:"flex", flexDirection:"column"}}>
      {/* <Chart datakey="contextInfo" param="username" type="sunburst"/> */}
      <CustomChart />   
      <Chart xkey="contextInfo" xparam="tcode" ykey="file" yparam="fileSizeDwn" type="sunburst"/>  
      <>{charts}</>
      <button type="button" class="btn btn-primary" onClick={()=>addNewChart()}>Add</button>
    </div>
  );
}

export default App;
