

function getRandomColor() {
    var letters = '0123456789ABCDEF';
    var color = '#';
    for (var i = 0; i < 6; i++) {
      color += letters[Math.floor(Math.random() * 16)];
    }
    return color;
  }


export const processData = (rawData, key, chartparam)=>{
    let userData = {};
    rawData.map((info,i)=>{
        let param = key ? info[key][chartparam] : info[chartparam];
        if(userData[param]){userData[param].push(info)}
        else userData[param] = [info]
        return null
    });
    return userData;
}

export const processData1 = (rawData, xkey, xparam, ykey, yparam)=>{
    let userData = {};
    rawData.map((info,i)=>{
        let param = xkey ? info[xkey][xparam] : info[xparam];
        if(xparam === "date_utc"){
            param = getddmmmDate(info.date_utc);
            // let dayOfWeek = new Date(info.date_utc).getDay()
            // param = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'][dayOfWeek]   
        }
        const getYdata = ()=>{
            if(ykey){
                if(yparam){
                    return info[ykey][yparam]
                }
                else{
                    return info[ykey]
                }
            }
            else{
                return info
            }
        }

        if(userData[param]){
            userData[param].push(getYdata())
        }
        else {
            userData[param] = [getYdata()]
        }
        return null
    });
    
    return userData;
}

export const processChartData = (indexedData, setChartData, param)=>{
    let cData = [];
    Object.keys(indexedData).map((id)=>{
      let obj = {};
      obj.name = id;
      obj.bigness = param === "fileSizeDwn" ? sumOfData(indexedData[id])/1000 : indexedData[id].length;
      obj.clr = getRandomColor()
      cData.push(obj);
      return null
    })
    if(setChartData){
        setChartData({children:cData});
    }
    else{
        return {children:cData}
    }
}

export const getBarchartData = (cData)=>{
    cData.children.map(rec=>{
      rec.x = rec.name;
      rec.y = rec.bigness
    })
    return cData.children;
}

export const removeDuplicates = (data)=>{
    let obj = {};
    Object.keys(data).map(key=>{
        obj[key] = [...new Set(data[key])]
    })
    return obj
}

