const getddmmmDate = (dstring)=>{
    let monthNames =["Jan","Feb","Mar","Apr",
                        "May","Jun","Jul","Aug",
                        "Sep", "Oct","Nov","Dec"];
    let d = new Date(dstring)
    let day = d.getDate();
    
    let monthIndex = d.getMonth();
    let monthName = monthNames[monthIndex];
    
    return `${day}-${monthName}`;  
}

export const getChildData = (data, params, value)=>{
    return data.filter((item)=>{
        if(params[0]){
            if(params[1]){
                return item[params[0]][params[1]] === value
            }
            else{
                return item[params[1]] === value
            }
        }
        else{
            return false
        }
    })
}