import React, { useEffect } from 'react';

import {
  XYPlot,
  XAxis,
  YAxis,
  VerticalGridLines,
  HorizontalGridLines,
  VerticalBarSeries,
  VerticalBarSeriesCanvas,
  DiscreteColorLegend,
  LabelSeries,
  LineMarkSeries,
  Hint
} from 'react-vis';
import {getBarchartData} from "./util";

function buildValue(hoveredCell) {
    const {radius, angle, angle0} = hoveredCell;
    const truedAngle = (angle + angle0) / 2;
    return {
        x: radius * Math.cos(truedAngle),
        y: radius * Math.sin(truedAngle)
    };
}

const tipStyle = {
    display: 'flex',
    color: '#fff',
    background: '#000',
    alignItems: 'center',
    padding: '5px'
};

// export default class Example extends React.Component {
function BarChart(props){
    const BarSeries = VerticalBarSeries;

    const parseData = (data)=>{
        data = getBarchartData(data)
        data.forEach(element => {
            element.rotation = 90;
        });
        return data;
    }

    return (
      <div>
        {
          props.hoveredCell &&
          <p style={{position:"absolute", left:"45%", top: 10, zIndex:100, padding: "3px 5px", background:"lightblue"}}>{props.hoveredCell.name + " | " + props.hoveredCell.bigness}</p>
        }
        <XYPlot
          className="clustered-stacked-bar-chart-example"
          xType="ordinal"
          stackBy="y"
          width={800}
          height={300}
        >
          <VerticalGridLines />
          <HorizontalGridLines />
          <XAxis tickLabelAngle={315} height={300} top={250}/>
          <YAxis />
          <BarSeries
            cluster="2016"
            color="#79C7E3"
            data={parseData(props.data)}
            style={{color:'red'}}
            onValueClick={(datapoint, event)=>{console.log(props); props.onDataSelect(datapoint)}}
            onValueRightClick={(datapoint,event)=>{props.hideDataCell(datapoint)}}
            onValueMouseOver={(datapoint, event)=>{props.setHoveredCell(datapoint)}}
            onValueMouseOut={(datapoint, event)=>{props.setHoveredCell(false)}}
          >
              {props.hoveredCell ? (
                <Hint value={buildValue(props.hoveredCell)}>
                    <div style={tipStyle}>
                        <p> user: {props.hoveredCell.name} / {props.hoveredCell.bigness} records</p>
                    </div>
                </Hint>
            ) : null}
          </BarSeries> 
        </XYPlot>
      </div>
    );
}

export default BarChart